#!/usr/bin/env bash
# Baseline smoke test for harness companion script hardening cycle.
# Generated by the initializer agent -- edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SCRIPTS_DIR="$PROJECT_ROOT/plugins/harness/scripts"

echo "=== Harness v2.2.1 Baseline Smoke Test ==="

# 1. Verify Node.js is available
if command -v node > /dev/null 2>&1; then
  NODE_VERSION=$(node --version)
  echo "OK -- Node.js available ($NODE_VERSION)"
else
  echo "FAIL -- Node.js not found in PATH"
  exit 1
fi

# 2. Verify scripts directory exists
if [ -d "$SCRIPTS_DIR" ]; then
  echo "OK -- scripts directory exists"
else
  echo "FAIL -- scripts directory not found at $SCRIPTS_DIR"
  exit 1
fi

# 3. Verify harness-companion.mjs entry point exists and parses
if [ -f "$SCRIPTS_DIR/harness-companion.mjs" ]; then
  echo "OK -- harness-companion.mjs exists"
else
  echo "FAIL -- harness-companion.mjs not found"
  exit 1
fi

if node --check "$SCRIPTS_DIR/harness-companion.mjs" 2>/dev/null; then
  echo "OK -- harness-companion.mjs parses cleanly"
else
  echo "FAIL -- harness-companion.mjs has syntax errors"
  exit 1
fi

# 4. Verify all 5 existing lib modules
LIBS="state.mjs features.mjs git.mjs artifacts.mjs progress.mjs"
for lib in $LIBS; do
  if [ -f "$SCRIPTS_DIR/lib/$lib" ]; then
    echo "OK -- lib/$lib exists"
  else
    echo "FAIL -- lib/$lib not found"
    exit 1
  fi
done

# 5. Verify harness state files exist
if [ -f "$PROJECT_ROOT/.harness/features.json" ] && [ -f "$PROJECT_ROOT/.harness/state.json" ]; then
  echo "OK -- harness state files present"
else
  echo "FAIL -- harness state files missing"
  exit 1
fi

# 6. Verify harness-companion.mjs responds to --help
if node "$SCRIPTS_DIR/harness-companion.mjs" --help > /dev/null 2>&1; then
  echo "OK -- harness-companion.mjs --help responds"
else
  echo "FAIL -- harness-companion.mjs --help did not respond"
  exit 1
fi

echo ""
echo "Baseline verified. Ready for sprint."
